mapper.select:
select distinct a.id, (select b.name from sys_org b where b.id = a.org_id and b.is_delete = 0 ) orgName, a.type, a.name, a.year, a.status, a.create_time, a.create_by, (select c.name from sys_user c where c.id = a.create_by ) createName, a.remark from xm_train_plan a left join xm_project p on a.id = p.train_plan_id and p.is_delete = 0 where a.is_delete = 0 and a.type = #{type}
and (a.org_id in (SELECT id FROM `sys_org` WHERE pids LIKE CONCAT('%[',#{orgId},']%')) or a.org_id = #{orgId})
and a.year = #{year}
and a.name like concat('%', #{name}, '%')
and p.id = #{projectId}
order by a.create_time desc
